mapper.sql:
WHERE user_id = #{userId}
AND is_deleted = 0

    AND license_plate LIKE CONCAT('%', #{req.licensePlate}, '%')


    AND visitor_name LIKE CONCAT('%', #{req.visitorName}, '%')


    AND visit_date = #{req.visitDate}

mapper.select:
SELECT vv.visitor_vehicle_id, vv.license_plate, vv.visitor_name, vv.visit_purpose, vv.visit_date, vv.status, u.name AS user_name, h.dong, h.ho FROM visitor_vehicle vv JOIN user u ON vv.user_id = u.user_id JOIN household h ON u.household_id = h.household_id WHERE vv.is_deleted = 0
AND vv.visit_date = #{visitDate}
AND vv.license_plate LIKE CONCAT('%', #{licensePlate}, '%')
ORDER BY vv.created_at DESC LIMIT #{startIdx}, #{size}

SELECT COUNT(*) FROM visitor_vehicle vv JOIN user u ON vv.user_id = u.user_id WHERE vv.is_deleted = 0
AND vv.visit_date = #{visitDate}
AND vv.license_plate LIKE CONCAT('%', #{licensePlate}, '%')

SELECT COUNT(*)
FROM visitor_vehicle
WHERE is_deleted = 0
    AND YEAR(visit_date) = #{year}
  AND MONTH(visit_date) = #{month}
